ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCrops ?child ; p:hasAgriculture_Reporters ?parent . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Agriculture_Reporters } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?description WHERE {
  ?agriculture_reporters_crops a :Agriculture_Reporters_Crops .
  ?crops a :Crops .
  ?agriculture_reporters_crops p:hasCrops ?crops .
  ?agriculture_reporters a :Agriculture_Reporters .
  ?agriculture_reporters_crops p:hasAgriculture_Reporters ?agriculture_reporters .
  ?agriculture_reporters p:name ?name .
  ?crops p:description ?description .
} }
}

